settings.custom_css:
:root {
  --rivo-color-light-gray: #f3f3f3;
  --rivo-color-light-pink: #f6eeee;
  --rivo-color-peach: #faefea;
  --rivo-color-mint: #e0e8e6;
  --rivo-color-cream: #fefaf0;
  --rivo-color-rose-tan: #e9d5cd;
}

@font-face {
  font-family: 'PT-Serif';
  font-style: normal;
  font-weight: 400;
  font-display: swap;
  src: url(https://fonts.gstatic.com/s/ptserif/v18/EJRVQgYoZZY2vCFuvAFWzr-_dSb_.woff2) format('woff2');
  unicode-range: U+0000-00FF, U+0131, U+0152-0153, U+02BB-02BC, U+02C6, U+02DA, U+02DC, U+0304, U+0308, U+0329, U+2000-206F, U+20AC, U+2122, U+2191, U+2193, U+2212, U+2215, U+FEFF, U+FFFD;
}
@font-face {
  font-family: 'PT-Serif';
  font-style: normal;
  font-weight: 700;
  font-display: swap;
  src: url(https://fonts.gstatic.com/s/ptserif/v18/EJRSQgYoZZY2vCFuvAnt66qSVyvVp8NA.woff2) format('woff2');
  unicode-range: U+0000-00FF, U+0131, U+0152-0153, U+02BB-02BC, U+02C6, U+02DA, U+02DC, U+0304, U+0308, U+0329, U+2000-206F, U+20AC, U+2122, U+2191, U+2193, U+2212, U+2215, U+FEFF, U+FFFD;
}

.rivo-hero-title,
.rivo-lp-section-title,
.rivo-how-it-works-step-title,
span.rivo-th-tier-name,
.rivo-modal__title {
  font-family: 'PT-Serif', serif !important;
}

/* --- HERO --- */
@media screen and (max-width: 769px) {
  .rivo-lp-cards-container {
    width: 100% !important;
  }
  .rivo-hero-banner-text {
    padding-top: 40px;
    padding-bottom: 40px;
  }
  #rivo-lp-header .rivo-lp-content {
    padding-left: 0;
    padding-right: 0;
  }
  .rivo-mobile-banner-overlay .rivo-lp-content {
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
  }
}

@media (min-width: 750px) {
  .rivo-hero-banner-wrapper {
    padding: 1rem;
  }
  .rivo-hero-banner-text {
    display: flex;
    flex-direction: column;
    height: 100%;
  }
  #rivo-lp-header {
    display: flex;
  }
  #rivo-ways-to-redeem .rivo-lp-section-subtitle {
    max-width: 50%;
    margin: 0 auto;
  }
  .rivo-how-it-works-step-subtitle {
    max-width: 70%;
    margin: 0 auto;
  }
}

/* --- BUTTONS --- */

.rivo-hero-buttons a,
.rivo-modal-button {
  background: #2b282f !important;
  border: none;
  color: #fff;
  text-transform: uppercase;
  font-weight: 500;
}

.rivo-modal-cta {
  width: fit-content;
  margin: 0 auto;
}

.rivo-modal-p a {
  text-decoration: underline;
}

@media (min-width: 769px) {
  .rivo-hero-buttons a {
    width: 45%;
  }
}

.rivo-modal-p a:after {
  content: ".";
}

.rivo-hero-buttons a:hover,
.rivo-modal-button:hover {
  background: #f8b68f !important;
  border: none;
  color: #000;
}

.rivo-hero-title {
  line-height: 1.1;
}

.rivo-hero-description {
  padding-top: 0;
}

/* --- STEPS --- */

.rivo-how-it-works-step-title {
  text-transform: lowercase !important;
  font-weight: 700;
}

.rivo-how-it-works-step-image img {
  margin: 0 auto;
}

.rivo-step-item {
  flex-basis: 33%;
  padding: 0 15px;
}

#rivo-ways-to-earn .rivo-lp-section-title {
  display: grid;
  line-height: 1.1;
}

#rivo-ways-to-earn .rivo-card {
  border: 3px solid var(--rivo-primary-color);
}

.rivo-arrow-icon {
  opacity: 1;
}

.rivo-card-description {
  padding-top: 0;
}

.rivo-lp-section-subtitle {
  padding-top: 5px;
}

.rivo-lp-section-title {
  line-height: 1.2;
}

/* --- VIP TIERS --- */
td.rivo-vip-tier-table-row-perk-name {
  text-align: left;
  font-weight: 600;
}

@media (min-width: 768px) and (max-width: 1024px) {
  span.rivo-th-tier-name {
    min-height: 60px;
    place-content: center;
    display: flex;
    align-items: center;
  }
}

span.rivo-th-tier-threshold {
  font-weight: 400;
  padding: 10px;
  text-transform: capitalize;
  font-weight: 500;
  width: 90%;
  margin: 0 auto;
}

.rivo-tier-column-1 span.rivo-th-tier-threshold {
  background: var(--rivo-color-light-gray);
}

.rivo-tier-column-2 span.rivo-th-tier-threshold {
  background: var(--rivo-color-light-pink);
}

.rivo-tier-column-3 span.rivo-th-tier-threshold {
  background: var(--rivo-color-peach);
}

.rivo-tier-column-4 span.rivo-th-tier-threshold {
  background: var(--rivo-color-mint);
}

span.rivo-th-tier-image {
  display: none;
}

/* --- ACTIVITY --- */

.rivo-points-expiry {
  padding: 10px;
  background: var(--rivo-color-light-gray);
  width: fit-content;
  margin: 0 auto;
  border-radius: 0.75rem;
  font-size: 14px;
  margin-top: 10px;
}

#rivo-lp-my-rewards .rivo-lp-content {
  padding: 25px;
  margin: 0 10px;
  border: 3px solid #000;
  border-radius: 10px;
  background: var(--rivo-color-cream);
}

@media (max-width: 768px) {
  .rivo-how-it-works-step-image img {
    height: 125px;
    margin: 0 auto;
  }

  .rivo-vip-tier-container {
    width: 100%;
    overflow: auto;
    position: relative;
  }

  table.rivo-vip-tier-table td,
  table.rivo-vip-tier-table th {
    width: 100px;
    height: 50px;
  }

  span.rivo-th-tier-name {
    font-size: 16px;
    height: 50px;
    align-content: center;
  }

  .rivo-vip-tier-table-thead-first-cell {
    background: #fff;
  }

  .rivo-vip-tier-table-thead-first-cell,
  td.rivo-vip-tier-table-row-perk-name {
    position: sticky;
    left: 0;
  }
}

/* —— VIP Tiers Progress Bar —— */

.rivo-vip-tier-progress-container {
  width: 50%;
}

@media (max-width: 768px) {
  .rivo-vip-tier-progress-container {
    width: 100%;
  }
}

.rivo-account-progress-bar {
  background: var(--rivo-secondary-color);
  padding-left: 20px;
  padding-right: 10px;
  color: #000;
}

.rivo-progress-current-tier-label,
.rivo-progress-next-tier-label {
  font-family: "PT Serif", sans-serif;
  font-weight: 700;
}

.rivo-account-progress-container {
  background-color: #fff !important;
  border: 2px solid #000 !important;
  border-radius: 100px;
}

#rivo-vip-tiers .rivo-lp-section-title {
  display: grid;
}

.rivo-lp-section-subheading {
  font-family: "Avenir Next" !important;
  text-transform: uppercase;
  font-size: 16px;
  font-weight: 400;
  margin-bottom: 15px;
}

#rivo-ways-to-earn .rivo-lp-section-title,
#rivo-vip-tiers .rivo-lp-section-title {
  display: grid;
}

/* --- MODAL --- */

input.rivo-coupon-code {
  font-size: 16px !important;
  border-radius: 5px;
   border: 1px solid #000;
}

.rivo-copy-button.rivo-success-button::before,
button[aria-label="Copy coupon code"]::before {
    background-image: url('https://cdn.shopify.com/s/files/1/0104/6904/8384/files/RIVO_Success_Button_Icon_fec3e94c-7c45-4164-bf5d-51fbf66c34ad.svg?v=1744605965') !important;
left: -10px;
}

/* --- SCROLL BAR --- */

/* Styles for WebKit-based browsers (Chrome, Safari, newer versions of Edge) */
.rivo-lp-cards-container::-webkit-scrollbar,
.rivo-vip-tier-container::-webkit-scrollbar {
  width: 10px;
  height: 8px;
}

.rivo-lp-cards-container::-webkit-scrollbar-track,
.rivo-vip-tier-container::-webkit-scrollbar-track {
  background: #dfe8e6;
  border-radius: 10px;
}

.rivo-lp-cards-container::-webkit-scrollbar-thumb,
.rivo-vip-tier-container::-webkit-scrollbar-thumb {
  background: #000;
  border-radius: 10px;
}

.rivo-lp-cards-container::-webkit-scrollbar-thumb:hover,
.rivo-vip-tier-container::-webkit-scrollbar-thumb:hover {
  background: #000;
}

#points-logs-activity th,
#points-logs-activity td {
  font-size: 14px;
}

#points-logs-activity th {
  background: #000;
  color: #fff;
}

#upload-receipt-attachment label.attachment-block,
#email-subscribe-container .dashed-block {
  margin-bottom: 20px;
  border: 1px dashed #000000;
}

#upload-receipt-container .text-description p {
  font-size: 14px !important;
}

iframe.rivo-referral {
  background: var(--rivo-color-rose-tan);
  height: 875px;
  transform: none;
  border-radius: 0;
}

@media only screen and (min-width: 900px) and (max-width: 1500px) {
  #rivo-ways-to-earn .rivo-lp-section-title {
    max-width: 70%;
    margin: 0 auto;
    margin-bottom: 15px;
  }
  #rivo-ways-to-redeem .rivo-lp-section-title {
    max-width: 50%;
    margin: 0 auto;
    margin-bottom: 15px;
  }
  #rivo-ways-to-earn .rivo-lp-section-subtitle,
  #rivo-ways-to-redeem .rivo-lp-section-subtitle {
    max-width: 50%;
    margin: 0 auto;
  }
}

.rivo-lp-section-title {
   margin-bottom: 15px;
}

/* --- MOBILE --- */
@media (max-width: 768px) {
  .rivo-lp-content {
    padding-left: 10px;
    padding-right: 10px;
  }

  #rivo-lp-header .rivo-lp-content {
    padding-left: 0;
    padding-right: 0;
  }
  .rivo-hero-banner-text {
    padding-top: 50px;
    padding-bottom: 50px;
  }

  .rivo-vip-tier-table tr:last-of-type td {
    border-bottom: none;
    padding-bottom: 25px;
  }
  .rivo-card:hover:not(.rivo-no-click) {
    transform: none;
  }
  #rivo-lp-my-rewards .rivo-lp-content {
    padding: 25px 15px;
  }
  #rivo-ways-to-earn .rivo-lp-cards-container {
    flex-flow: row nowrap; /* Prevent wrapping */
    justify-content: flex-start; /* Align items to the start */
    overflow-x: auto; /* Enable horizontal scrolling */
    scroll-behavior: smooth; /* Add smooth scrolling */
  }

  /* --- Scroll the ways to earn cards on mobile --- */
  #rivo-ways-to-earn .rivo-card {
    flex: 0 0 auto;
    width: auto;
    max-width: 150px;
    margin-bottom: 10px;
  }
  iframe.rivo-referral {
    height: 1025px;
    width:  -webkit-fill-available;
  }
  #rivo-lp-referral-campaign .rivo-lp-content,
  #rivo-vip-tiers .rivo-lp-content {
    padding: 0;
  }
}
